  # Group predicate phrases by subject to avoid repeating the subject.
      subject_phrases: dict[str, list[str]] = {}
      for t in triples:
          template = pred_map.get(t.predicate, "{pred} is {obj}")
          if "{pred}" in template:
              phrase = template.format(pred=t.predicate, obj=t.object)
          else:
              phrase = template.format(obj=t.object)
          subject_phrases.setdefault(t.subject, []).append(phrase)

      # Build one sentence per distinct subject, then join them.
      sentences: list[str] = []
      for subj, phrases in subject_phrases.items():
          if len(phrases) == 1:
              sentences.append(f"{subj} {phrases[0]}.")
          else:
              body = ", ".join(phrases[:-1]) + ", and " + phrases[-1]
              sentences.append(f"{subj} {body}.")
      sentence = " ".join(sentences)
      return sentence
